    width: 320px;
    background: #fff;
    border-radius: 8px;
    box-shadow: 0 4px 15px rgba(0, 0, 0, 0.1);
    padding: 25px;
    display: flex;
    flex-direction: column;
    height: calc(100vh - 40px);
    position: sticky;
    top: 20px;
}

