    text-align: center;
    font-size: 1.3rem;
    font-weight: 600;
}

.pane-buttons {
    display: flex;
    flex-direction: column;
    gap: 18px;
    margin-bottom: 30px;
}

.pane-btn {
    padding: 16px 20px;
    border: none;
