}

.row {
    display: flex;
    gap: 20px;
    flex-wrap: wrap;
}

.col {
    flex: 1;
    min-width: 250px;
}

/* MNQF CSS */
.mnqf-container {
    display: flex;
    align-items: center;
    border: 1px solid #ccc;
    border-radius: 4px;
    padding: 5px;
    background-color: white;
    margin-top: 5px;
}

.mnqf-container input {
    border: none;
    outline: none;
    width: 50px;
    margin-top: 0;
    font-size: 16px;
}

.mnqf-label {
    color: #555;
    font-style: italic;
    margin-left: 5px;
    white-space: nowrap;
}

/* Table Styles */
table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 0;
    font-size: 14px;
    height: 100%;
}

th,
td {
    border: 1px solid var(--border-color);
    padding: 8px;
    text-align: left;
    vertical-align: middle;
}

th {
    background-color: #f8f9fa;
    color: var(--primary-color);
    font-weight: bold;
}

.total-row td {
    background-color: #e9ecef;
    font-weight: bold;
}

/* --- 11.3 Layout Consistency Styles --- */
.equal-row {
    display: flex;
    gap: 20px;
    flex-wrap: wrap;
    align-items: stretch;
}

.equal-col {
    flex: 1 1 0;
    min-width: 300px;
    display: flex;
    flex-direction: column;
}

.calc-box {
    flex: 1;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
    background: #f0f8ff;
    padding: 20px;
    border-radius: 5px;
    border: 1px solid #b8daff;
}

.calc-input {
    background-color: #e9ecef;
    color: #555;
    font-weight: bold;
}

.dist-box {
    flex: 1;
    display: flex;
    flex-direction: column;
    background: #fff;
    padding: 20px;
    border-radius: 5px;
    border: 1px solid #ddd;
}

/* Auto-resize textarea styles */
textarea.auto-resize {
    overflow: hidden;
    resize: none;
}

/* Assessment wrapper styles */
.assessment-wrapper {
    font-family: Arial, sans-serif;
    padding: 10px;
    box-sizing: border-box;
}

.assessment-wrapper * {
    box-sizing: border-box;
}

.assessment-wrapper table {
    width: 100%;
    border-collapse: collapse;
    margin-top: 10px;
    margin-bottom: 20px;
    table-layout: fixed;
}

.assessment-wrapper th,
.assessment-wrapper td {
    border: 1px solid #ccc;
    padding: 8px;
    vertical-align: top;
}

.assessment-wrapper th {
    background-color: #f2f2f2;
    text-align: left;
    font-size: 14px;
}

.assessment-wrapper input[type="text"],
.assessment-wrapper input[type="number"],
.assessment-wrapper select {
    width: 100%;
    padding: 5px;
    height: 35px;
    border: 1px solid #999;
    border-radius: 3px;
}

.assessment-wrapper textarea {
    width: 100%;
    padding: 5px;
    resize: none;
    overflow: hidden;
    min-height: 35px;
    font-family: Arial, sans-serif;
    border: 1px solid #999;
    border-radius: 3px;
    display: block;
    line-height: 1.4;
}

/* Outcome table styles */
.outcome-table {
    width: 100%;
    border-collapse: collapse;
    margin-bottom: 15px;
}

.outcome-table th,
.outcome-table td {
    border: 1px solid #ccc;
    padding: 8px;
    vertical-align: middle;
}

.outcome-table th:first-child,
.outcome-table td:first-child {
    width: 350px;
    min-width: 300px;
}

.vertical-header {
    width: 30px; /* narrow column for vertical header */
    padding: 0;
    vertical-align: middle;
    text-align: center;
    /* Ensure enough height for rotated text */
    height: auto;
}

.vertical-header div {
    /* Use transform rotation for better PDF rendering */
    transform: rotate(-90deg);
    transform-origin: left top;
    white-space: nowrap;
    margin: 0;
    /* Optional: adjust spacing */
    padding: 5px 0;
}

.checkbox-cell {
    text-align: center;
    width: 1%;
}

.outcome-input-wrapper {
    display: flex;
    align-items: flex-start;
    width: 100%;
}

.outcome-input-wrapper span {
    margin-right: 8px;
    font-weight: bold;
    margin-top: 5px;
}

.outcome-input-wrapper textarea {
    flex: 1;
    padding: 5px;
    resize: vertical;
    font-family: Arial, sans-serif;
    box-sizing: border-box;
    line-height: 1.4;
    overflow: auto;
}

.add-btn {
    background-color: #28a745;
    color: white;
    padding: 10px 20px;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 14px;
    font-weight: bold;
}

.add-btn:hover {
    background-color: #218838;
}

/* Progress bar styles for assessment */
.summary-box {
    display: flex;
    justify-content: space-between;
    margin-bottom: 20px;
    padding: 15px;
    background: #f8f9fa;
    border-radius: 6px;
    border: 1px solid #ddd;
}

.summary-stats-col {
    flex: 1;
}

.summary-warning-col {
    flex: 0 0 300px;
    display: flex;
    align-items: center;
}

.warning-text {
    color: #dc3545;
    font-weight: bold;
    font-size: 0.9em;
    display: none;
}

.progress-container {
    position: relative;
    height: 30px;
    background: #e9ecef;
    border-radius: 4px;
    margin-top: 10px;
    overflow: hidden;
}

.marker-50 {
    position: absolute;
    left: 50%;
    height: 100%;
    width: 2px;
    background: #dc3545;
    z-index: 1;
}

.progress-bar-controlled {
    position: absolute;
    height: 100%;
    background: #007bff;
    transition: width 0.3s;
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 2;
}

.progress-bar-uncontrolled {
    position: absolute;
    height: 100%;
    background: #6c757d;
    transition: width 0.3s;
    display: flex;
    align-items: center;
    justify-content: center;
    z-index: 2;
}

.bar-label {
    color: white;
    font-weight: bold;
    font-size: 0.8em;
    text-shadow: 1px 1px 1px rgba(0, 0, 0, 0.3);
}

.btn {
    padding: 8px 16px;
    border: none;
    border-radius: 4px;
    cursor: pointer;
    font-size: 14px;
    margin-right: 10px;
}

.btn-green {
    background-color: #28a745;
    color: white;
}

.btn-red {
    background-color: #dc3545;
    color: white;
}

/* Print styles for PDF export */
@media print {
    body {
        background: white !important;
        color: black !important;
        padding: 0 !important;
        margin: 0 !important;
        font-size: 12px !important;
        line-height: 1.4 !important;
    }

    .side-pane,
    .pane-btn,
    .add-btn,
    button,
    .modal,
    .notification-popup,
    .dist-box {
        display: none !important;
    }

    .container {
        box-shadow: none !important;
        padding: 10px !important;
        margin: 0 !important;
        width: 100% !important;
        max-width: 100% !important;
    }

    .main-container {
        width: 100% !important;
        max-width: 100% !important;
        margin: 0 !important;
    }

    /* Page break control for PDF */
    .page-break {
        page-break-before: always;
    }

    /* Remove all borders from sections */
    .section {
        background: white !important;
        border: none !important;
        box-shadow: none !important;
        padding: 10px 0 !important;
        margin-bottom: 15px !important;
        page-break-inside: avoid;
    }

    /* Remove colored backgrounds */
    .calc-box {
        background: white !important;
        border: none !important;
        padding: 10px 0 !important;
    }

    .calc-input,
    th,
    .total-row td {
        background: white !important;
    }

    /* Hide specific elements */
    #controlledWarning,
    .warning-text {
        display: none !important;
    }

    /* Remove background color from 11.10 section */
    .assessment-wrapper .section {
        background: white !important;
    }

    /* Remove yellow background from assessment note */
    .assessment-wrapper>.section>div[style*="background: #fff3cd"] {
        background: white !important;
        border: 1px solid #ddd !important;
    }

    /* Style for headers */
    h1 {
        color: black !important;
        border-bottom: 1px solid #000 !important;
        font-size: 18px !important;
        margin-bottom: 15px !important;
        padding-bottom: 5px !important;
    }

    h2 {
        color: black !important;
        border-left: 3px solid #666 !important;
        font-size: 14px !important;
        margin-bottom: 8px !important;
        padding-left: 5px !important;
    }

    /* Reduce font size proportionally */
    body,
    input,
    textarea,
    select,
    label,
    th,
    td {
        font-size: 11px !important;
    }

    /* Fix for outcome table headers - make them horizontal */
    .vertical-header {
        height: auto !important;
        width: auto !important;
        white-space: normal !important;
        text-align: center !important;
    }

    .vertical-header div {
        writing-mode: horizontal-tb !important;
        transform: none !important;
        width: 100% !important;
        height: auto !important;
        padding: 3px !important;
        font-size: 10px !important;
    }

    /* Input field styling for PDF */
    input,
    textarea,
    select {
        border: 1px solid #999 !important;
        background: white !important;
        box-shadow: none !important;
        outline: none !important;
        color: black !important;
        font-size: 11px !important;
        padding: 4px !important;
        margin-top: 2px !important;
    }

    input[readonly],
    textarea[readonly] {
        background: #f9f9f9 !important;
    }

    table {
        border: 1px solid #ddd !important;
        font-size: 11px !important;
    }

    th,
    td {
        border: 1px solid #ddd !important;
        color: black !important;
        padding: 4px !important;
        font-size: 11px !important;
    }

    /* Hide the main title "Module Outline Form" */
    h1:first-of-type {
        display: none !important;
    }

    /* Page break before section 11.9 */
    #section11_9 {
        page-break-before: always;
    }

    /* Adjust table sizes for smaller font */
    .outcome-table th:first-child,
    .outcome-table td:first-child {
        width: 200px !important;
        min-width: 200px !important;
    }

    /* Reduce padding in tables */
    .outcome-table th,
    .outcome-table td {
        padding: 4px !important;
    }

    /* Adjust textarea heights */
    textarea {
        min-height: 25px !important;
    }

    /* Adjust row spacing */
    .row {
        gap: 10px !important;
    }

    .col {
        min-width: 150px !important;
    }

    /* Hide contact and non-contact distribution tables */
    .dist-box {
        display: none !important;
    }

    /* Hide progress bars and summary boxes in PDF */
    .summary-box,
    .progress-container {
        display: none !important;
    }
}
